    'shadow-boxing': {
        1: { title: "노빠꾸 뒷북 섀도복싱 지수 빌런", body: ["당신의 뒷북 섀도복싱 지수 수치는 폭주 기관차 수준입니다. 브레이크 없이 앞만 보고 내달리네요.", "조금이라도 내 뜻대로 안 되면 다 엎어버리는 독불장군 성향이 여기까지 느껴집니다."], insight: "팩트폭행: 제발 혼자 살 거 아니면 주변 눈치 좀 보고 속도 좀 줄이세요." },
        2: { title: "소심한 뒷북 섀도복싱 지수 과몰입러", body: ["남들은 신경도 안 쓰는데 혼자서 뒷북 섀도복싱 지수 에 과몰입해서 밤잠을 설치고 있습니다.", "겉으로는 평온해 보이지만 속은 이미 소설 3권을 넘게 쓰고도 남을 찌질함의 극치입니다."], insight: "팩트폭행: 남들은 당신에게 그만큼 관심이 없으니 제발 상상의 나래 좀 그만 펼치세요." },
        3: { title: "관종력 100% 뒷북 섀도복싱 지수", body: ["재밌고 흥미로운 일만 쫓다 보니 뒷북 섀도복싱 지수 에 대한 진지함은 안드로메다로 날아갔습니다.", "입만 열면 과장이 심해져서 이제는 어디서부터 어디까지가 진실인지 본인도 모릅니다."], insight: "팩트폭행: 순간의 재미만 쫓다가는 평생 철딱서니 없는 베짱이로 남을 겁니다." },
        4: { title: "FM 꼰대형 뒷북 섀도복싱 지수", body: ["당신의 뒷북 섀도복싱 지수 스타일은 숨막히는 답답함과 고지식함으로 가득 차 있습니다.", "본인이 정해둔 선을 조금이라도 넘으면 속으로 이미 상대방 손절각을 세우고 있네요."], insight: "팩트폭행: 융통성이라곤 1도 없는 꽉 막힌 태도. 주변 사람들이 다 떠나가기 전에 유들유들해지세요." },
        5: { title: "변덕쟁이 뒷북 섀도복싱 지수 도주자", body: ["처음엔 뒷북 섀도복싱 지수 에 대해서 호기심 천국이다가도 3일이면 흥미가 짜게 식어버립니다.", "조금이라도 구속당하거나 책임감이 생기면 이미 마음은 남미 한복판으로 도망쳤습니다."], insight: "팩트폭행: 자유로운 영혼인 척 하지만 사실은 그냥 끈기와 책임감이 없는 회피형일 뿐입니다." },
        6: { title: "오지랖 만렙 뒷북 섀도복싱 지수", body: ["남의 일에 감 놔라 배 놔라 참견하면서 본인의 뒷북 섀도복싱 지수 에 오지랖을 부리고 있습니다.", "상대는 원하지도 않는데 혼자 다 챙겨주려다가 나중엔 왜 안 알아주냐며 징징댑니다."], insight: "팩트폭행: 제발 선 넘지 말고 본인 앞가림이나 먼저 똑바로 하세요. 부담스럽습니다." },
        7: { title: "팩트폭행 뒷북 섀도복싱 지수 분석가", body: ["모든 것을 머리로 계산하고 분석하며 뒷북 섀도복싱 지수 에 대해 너무 차갑게 접근합니다.", "본인은 객관적이라고 믿지만 남들이 보기엔 그저 감정 없는 로봇이나 재수 없는 지식인입니다."], insight: "팩트폭행: 머리만 굴리지 말고 가슴 좀 써보세요. 아는 척하는 그 태도에 정떨어집니다." },
        8: { title: "통제광 뒷북 섀도복싱 지수 보스", body: ["모든 상황이 내 통제 안에 있어야 직성이 풀리는 극강의 꼰대력과 뒷북 섀도복싱 지수.", "자기가 세상의 중심인 양 행동하며 남들에게 지시하는 걸 너무 좋아해서 주변이 피곤합니다."], insight: "팩트폭행: 당신은 왕이 아닙니다. 남들의 의견을 무시하다간 언젠가 큰코 다치고 고립될 겁니다." },
        9: { title: "망상러 뒷북 섀도복싱 지수 몽상가", body: ["현실 도피적인 마인드로 뒷북 섀도복싱 지수 에 대해 혼자만의 유토피아를 건설하고 있습니다.", "착한 척, 다 이해하는 척하지만 실상은 갈등을 직면하기 싫어 덮어두려는 비겁함입니다."], insight: "팩트폭행: 대의명분 운운하기 전에 당장 눈앞의 꼬인 실타래부터 현실적으로 푸세요." },
    },
